// // This module implements a 2-bit shift register with parallel load capability.
// On reset, the output is set to 11 instead of 00.
// When the load input is asserted, the data input is loaded into the register.
// Otherwise, on each clock edge, the data in the register shifts right by one bit, with the most significant bit being filled with '1'.
// The output of the register is visible on a 2-bit output signal.
module shift_register (
    input clk,
    input reset,
    input load,
    input [1:0] data_in,
    output reg [1:0] data_out
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out <= 2'b00;
        end else if (load) begin
            data_out <= data_in;
        end else begin
            data_out <= {data_out[0], 1'b0}; // Shift left and fill LSB with 0
        end
    end
endmodule

